module top_module(
    input A,
    input B,
    input C,
    input D,
    output Y
);wire not_and_result;
    wire or_gate_out;

    // AND gate implementation
    assign not_and_result = A & B & C;

    // OR gate implementation
    assign or_gate_out = A | B;

    // Final output implementation
    assign Y = not_and_result | D | or_gate_out;

endmodule
